import { describe, it, expect } from "vitest";
import { nextGeneration } from "./game-of-life.js";

describe("Game of Life - nextGeneration", () => {
  // Simplest case: single cell with no neighbors (Rule 1 - Underpopulation)
  it.todo("single live cell dies from underpopulation -- [(0,0)] -> []");

  // Rule 1 - Underpopulation: two adjacent cells each have only 1 neighbor
  it.todo("two horizontally-adjacent cells both die from underpopulation -- [(0,1),(1,1)] -> []");

  // Rule 3 - Overpopulation: center cell has 4+ neighbors and dies
  it.todo("center cell with 4 live neighbors dies from overpopulation (rule 3 example) -- center (1,1) dies");

  // Rule 4 - Reproduction: dead cell with exactly 3 live neighbors becomes alive
  it.todo("dead cell with exactly 3 live neighbors becomes alive (rule 4 example) -- (1,1) becomes alive");

  // Rule 2 - Survival: live cell with 2 or 3 neighbors lives on (rule 2 example)
  it.todo("center cell with 3 live neighbors survives (rule 2 example) -- center (1,1) survives");

  // Block still life (Rule 2 + no Rule 4 triggers)
  it.todo("block pattern is a still life -- [(0,0),(1,0),(0,1),(1,1)] unchanged");

  // Blinker oscillator Gen 0 -> Gen 1
  it.todo("vertical blinker becomes horizontal -- [(0,0),(0,1),(0,2)] -> [(-1,1),(0,1),(1,1)]");

  // Blinker oscillator Gen 1 -> Gen 2 (back to vertical)
  it.todo("horizontal blinker becomes vertical -- [(-1,1),(0,1),(1,1)] -> [(0,0),(0,1),(0,2)]");

  // Negative coordinates handling
  it.todo("handles negative coordinates -- block at negative coords is still life");
});

export type Cell = [number, number];

export function nextGeneration(cells: Cell[]): Cell[] {
  throw new Error("Not implemented");
}

