export type Cell = [number, number];

export function nextGeneration(cells: Cell[]): Cell[] {
  const key = (x: number, y: number): string => `${x},${y}`;
  const alive = new Set<string>();
  for (const [x, y] of cells) alive.add(key(x, y));

  // Count live neighbors for every cell that has at least one live neighbor
  const neighborCounts = new Map<string, number>();
  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const k = key(x + dx, y + dy);
        neighborCounts.set(k, (neighborCounts.get(k) ?? 0) + 1);
      }
    }
  }

  const next: Cell[] = [];
  // A cell is alive in next gen if it has 3 neighbors (reproduction or survival)
  // or if it is currently alive and has 2 neighbors (survival).
  for (const [k, count] of neighborCounts) {
    const [xs, ys] = k.split(",");
    const x = Number(xs);
    const y = Number(ys);
    if (count === 3 || (count === 2 && alive.has(k))) {
      next.push([x, y]);
    }
  }
  return next;
}

